import{_ as e,o,c as a,ai as i}from"./chunks/framework.CsYGeNYI.js";const g=JSON.parse(`{"title":"沙箱 vs 工具策略 vs 提权","description":"","frontmatter":{"read_when":"You hit 'sandbox jail' or see a tool/elevated refusal and want the exact config key to change.","status":"active","summary":"工具被阻止的原因：沙箱运行时、工具允许/拒绝策略和提权 exec 限制","title":"沙箱 vs 工具策略 vs 提权","x-i18n":{"generated_at":"2026-02-03T07:48:55Z","model":"claude-opus-4-5","provider":"pi","source_hash":"863ea5e6d137dfb61f12bd686b9557d6df1fd0c13ba5f15861bf72248bc975f1","source_path":"gateway/sandbox-vs-tool-policy-vs-elevated.md","workflow":15}},"headers":[],"relativePath":"zh-CN/gateway/sandbox-vs-tool-policy-vs-elevated.md","filePath":"zh-CN/gateway/sandbox-vs-tool-policy-vs-elevated.md","lastUpdated":null}`),l={name:"zh-CN/gateway/sandbox-vs-tool-policy-vs-elevated.md"};function d(n,s,t,c,p,r){return o(),a("div",null,[...s[0]||(s[0]=[i(`<h1 id="沙箱-vs-工具策略-vs-提权" tabindex="-1"><a class="header-anchor" href="#沙箱-vs-工具策略-vs-提权">#</a> 沙箱 vs 工具策略 vs 提权</h1><p>OpenSoul 有三个相关（但不同）的控制：</p><ol><li><strong>沙箱</strong>（<code>agents.defaults.sandbox.*</code> / <code>agents.list[].sandbox.*</code>）决定<strong>工具在哪里运行</strong>（Docker vs 主机）。</li><li><strong>工具策略</strong>（<code>tools.*</code>、<code>tools.sandbox.tools.*</code>、<code>agents.list[].tools.*</code>）决定<strong>哪些工具可用/允许</strong>。</li><li><strong>提权</strong>（<code>tools.elevated.*</code>、<code>agents.list[].tools.elevated.*</code>）是一个<strong>仅限 exec 的逃逸通道</strong>，允许在沙箱隔离时在主机上运行。</li></ol><h2 id="快速调试" tabindex="-1"><a class="header-anchor" href="#快速调试">#</a> 快速调试</h2><p>使用检查器查看 OpenSoul <em>实际</em>在做什么：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sandbox</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> explain</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sandbox</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> explain</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --session</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> agent:main:main</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sandbox</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> explain</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --agent</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> work</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sandbox</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> explain</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --json</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>它会打印：</p><ul><li>生效的沙箱模式/范围/工作区访问</li><li>会话当前是否被沙箱隔离（主 vs 非主）</li><li>生效的沙箱工具允许/拒绝（以及它来自智能体/全局/默认哪里）</li><li>提权限制和修复键路径</li></ul><h2 id="沙箱-工具在哪里运行" tabindex="-1"><a class="header-anchor" href="#沙箱-工具在哪里运行">#</a> 沙箱：工具在哪里运行</h2><p>沙箱隔离由 <code>agents.defaults.sandbox.mode</code> 控制：</p><ul><li><code>&quot;off&quot;</code>：所有内容在主机上运行。</li><li><code>&quot;non-main&quot;</code>：仅非主会话被沙箱隔离（群组/渠道的常见&quot;意外&quot;）。</li><li><code>&quot;all&quot;</code>：所有内容都被沙箱隔离。</li></ul><p>参见<a href="/docs/gateway/sandboxing">沙箱隔离</a>了解完整矩阵（范围、工作区挂载、镜像）。</p><h3 id="绑定挂载-安全快速检查" tabindex="-1"><a class="header-anchor" href="#绑定挂载-安全快速检查">#</a> 绑定挂载（安全快速检查）</h3><ul><li><code>docker.binds</code> <em>穿透</em>沙箱文件系统：你挂载的任何内容在容器内以你设置的模式（<code>:ro</code> 或 <code>:rw</code>）可见。</li><li>如果省略模式，默认为读写；对于源代码/密钥优先使用 <code>:ro</code>。</li><li><code>scope: &quot;shared&quot;</code> 忽略每个智能体的绑定（仅全局绑定适用）。</li><li>绑定 <code>/var/run/docker.sock</code> 实际上将主机控制权交给沙箱；只有在有意为之时才这样做。</li><li>工作区访问（<code>workspaceAccess: &quot;ro&quot;</code>/<code>&quot;rw&quot;</code>）独立于绑定模式。</li></ul><h2 id="工具策略-哪些工具存在-可调用" tabindex="-1"><a class="header-anchor" href="#工具策略-哪些工具存在-可调用">#</a> 工具策略：哪些工具存在/可调用</h2><p>两个层次很重要：</p><ul><li><strong>工具配置文件</strong>：<code>tools.profile</code> 和 <code>agents.list[].tools.profile</code>（基础允许列表）</li><li><strong>提供商工具配置文件</strong>：<code>tools.byProvider[provider].profile</code> 和 <code>agents.list[].tools.byProvider[provider].profile</code></li><li><strong>全局/每个智能体工具策略</strong>：<code>tools.allow</code>/<code>tools.deny</code> 和 <code>agents.list[].tools.allow</code>/<code>agents.list[].tools.deny</code></li><li><strong>提供商工具策略</strong>：<code>tools.byProvider[provider].allow/deny</code> 和 <code>agents.list[].tools.byProvider[provider].allow/deny</code></li><li><strong>沙箱工具策略</strong>（仅在沙箱隔离时适用）：<code>tools.sandbox.tools.allow</code>/<code>tools.sandbox.tools.deny</code> 和 <code>agents.list[].tools.sandbox.tools.*</code></li></ul><p>经验法则：</p><ul><li><code>deny</code> 始终优先。</li><li>如果 <code>allow</code> 非空，其他所有内容都被视为阻止。</li><li>工具策略是硬性停止：<code>/exec</code> 无法覆盖被拒绝的 <code>exec</code> 工具。</li><li><code>/exec</code> 仅为授权发送者更改会话默认值；它不授予工具访问权限。 提供商工具键接受 <code>provider</code>（例如 <code>google-antigravity</code>）或 <code>provider/model</code>（例如 <code>openai/gpt-5.2</code>）。</li></ul><h3 id="工具组-简写" tabindex="-1"><a class="header-anchor" href="#工具组-简写">#</a> 工具组（简写）</h3><p>工具策略（全局、智能体、沙箱）支持 <code>group:*</code> 条目，它们会展开为多个工具：</p><div class="language-json5 vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  tools</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    sandbox</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">      tools</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        allow</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;group:runtime&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;group:fs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;group:sessions&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;group:memory&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>可用的组：</p><ul><li><code>group:runtime</code>：<code>exec</code>、<code>bash</code>、<code>process</code></li><li><code>group:fs</code>：<code>read</code>、<code>write</code>、<code>edit</code>、<code>apply_patch</code></li><li><code>group:sessions</code>：<code>sessions_list</code>、<code>sessions_history</code>、<code>sessions_send</code>、<code>sessions_spawn</code>、<code>session_status</code></li><li><code>group:memory</code>：<code>memory_search</code>、<code>memory_get</code></li><li><code>group:ui</code>：<code>browser</code>、<code>canvas</code></li><li><code>group:automation</code>：<code>cron</code>、<code>gateway</code></li><li><code>group:messaging</code>：<code>message</code></li><li><code>group:nodes</code>：<code>nodes</code></li><li><code>group:opensoul</code>：所有内置 OpenSoul 工具（不包括提供商插件）</li></ul><h2 id="提权-仅限-exec-的-在主机上运行" tabindex="-1"><a class="header-anchor" href="#提权-仅限-exec-的-在主机上运行">#</a> 提权：仅限 exec 的&quot;在主机上运行&quot;</h2><p>提权<strong>不会</strong>授予额外工具；它仅影响 <code>exec</code>。</p><ul><li>如果你被沙箱隔离，<code>/elevated on</code>（或带 <code>elevated: true</code> 的 <code>exec</code>）在主机上运行（审批可能仍然适用）。</li><li>使用 <code>/elevated full</code> 跳过该会话的 exec 审批。</li><li>如果你已经直接运行，提权实际上是空操作（仍然受限）。</li><li>提权<strong>不是</strong> skill 范围的，<strong>不会</strong>覆盖工具允许/拒绝。</li><li><code>/exec</code> 与提权是分开的。它仅为授权发送者调整每个会话的 exec 默认值。</li></ul><p>限制：</p><ul><li>启用：<code>tools.elevated.enabled</code>（以及可选的 <code>agents.list[].tools.elevated.enabled</code>）</li><li>发送者允许列表：<code>tools.elevated.allowFrom.&lt;provider&gt;</code>（以及可选的 <code>agents.list[].tools.elevated.allowFrom.&lt;provider&gt;</code>）</li></ul><p>参见<a href="/docs/tools/elevated">提权模式</a>。</p><h2 id="常见-沙箱困境-修复" tabindex="-1"><a class="header-anchor" href="#常见-沙箱困境-修复">#</a> 常见&quot;沙箱困境&quot;修复</h2><h3 id="工具-x-被沙箱工具策略阻止" tabindex="-1"><a class="header-anchor" href="#工具-x-被沙箱工具策略阻止">#</a> &quot;工具 X 被沙箱工具策略阻止&quot;</h3><p>修复键（选一个）：</p><ul><li>禁用沙箱：<code>agents.defaults.sandbox.mode=off</code>（或每个智能体 <code>agents.list[].sandbox.mode=off</code>）</li><li>在沙箱内允许该工具： <ul><li>从 <code>tools.sandbox.tools.deny</code> 中移除它（或每个智能体 <code>agents.list[].tools.sandbox.tools.deny</code>）</li><li>或将它添加到 <code>tools.sandbox.tools.allow</code>（或每个智能体 allow）</li></ul></li></ul><h3 id="我以为这是主会话-为什么被沙箱隔离了" tabindex="-1"><a class="header-anchor" href="#我以为这是主会话-为什么被沙箱隔离了">#</a> &quot;我以为这是主会话，为什么被沙箱隔离了？&quot;</h3><p>在 <code>&quot;non-main&quot;</code> 模式下，群组/渠道键<em>不是</em>主会话。使用主会话键（由 <code>sandbox explain</code> 显示）或将模式切换为 <code>&quot;off&quot;</code>。</p>`,36)])])}const k=e(l,[["render",d]]);export{g as __pageData,k as default};
